#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char type; scanf(" %c",&type);
        if(type=='R'){
            int l,w; scanf("%d %d",&l,&w);
            printf("%d %d
", l*w, 2*(l+w));
        }else if(type=='S'){
            int s; scanf("%d",&s);
            printf("%d %d
", s*s, 4*s);
        }
    }
    return 0;
}

